  1→import {
  2→	createContext,
  3→	type ReactNode,
  4→	useContext,
  5→	useEffect,
  6→	useState,
  7→} from "react";
  8→import { authClient } from "../lib/auth-client";
  9→
 10→interface Organization {
 11→	id: string;
 12→	name: string;
 13→	slug: string;
 14→	logo?: string | null | undefined;
 15→}
 16→
 17→interface OrganizationContextType {
 18→	activeOrg: Organization | null;
 19→	organizations: readonly Organization[];
 20→	switchOrg: (orgId: string) => Promise<void>;
 21→	isLoading: boolean;
 22→}
 23→
 24→const ACTIVE_ORG_CACHE_KEY = "rudel:activeOrg";
 25→
 26→function getCachedOrg(): Organization | null {
 27→	try {
 28→		const raw = localStorage.getItem(ACTIVE_ORG_CACHE_KEY);
 29→		if (!raw) return null;
 30→		const parsed = JSON.parse(raw);
 31→		if (parsed && typeof parsed.id === "string") return parsed;
 32→	} catch {
 33→		// Corrupted cache, ignore
 34→	}
 35→	return null;
 36→}
 37→
 38→function setCachedOrg(org: Organization | null) {
 39→	try {
 40→		if (org) {
 41→			localStorage.setItem(ACTIVE_ORG_CACHE_KEY, JSON.stringify(org));
 42→		} else {
 43→			localStorage.removeItem(ACTIVE_ORG_CACHE_KEY);
 44→		}
 45→	} catch {
 46→		// Storage full or unavailable, ignore
 47→	}
 48→}
 49→
 50→const OrganizationContext = createContext<OrganizationContextType | undefined>(
 51→	undefined,
 52→);
 53→
 54→export function OrganizationProvider({ children }: { children: ReactNode }) {
 55→	const { data: activeOrg, isPending: activeLoading } =
 56→		authClient.useActiveOrganization();
 57→	const { data: orgs, isPending: listLoading } =
 58→		authClient.useListOrganizations();
 59→	const [switching, setSwitching] = useState(false);
 60→	const [cachedOrg] = useState(getCachedOrg);
 61→
 62→	// Persist active org to localStorage whenever it changes
 63→	useEffect(() => {
 64→		if (activeOrg) {
 65→			setCachedOrg({
 66→				id: activeOrg.id,
 67→				name: activeOrg.name,
 68→				slug: activeOrg.slug,
 69→				logo: activeOrg.logo,
 70→			});
 71→		}
 72→	}, [activeOrg]);
 73→
 74→	// Auto-set active org if none is set but user has orgs
 75→	useEffect(() => {
 76→		if (
 77→			!activeLoading &&
 78→			!listLoading &&
 79→			!activeOrg &&
 80→			orgs &&
 81→			orgs.length > 0 &&
 82→			!switching
 83→		) {
 84→			setSwitching(true);
 85→			authClient.organization
 86→				.setActive({ organizationId: orgs[0].id })
 87→				.finally(() => setSwitching(false));
 88→		}
 89→	}, [activeOrg, orgs, activeLoading, listLoading, switching]);
 90→
 91→	const switchOrg = async (orgId: string) => {
 92→		setSwitching(true);
 93→		try {
 94→			await authClient.organization.setActive({ organizationId: orgId });
 95→		} finally {
 96→			setSwitching(false);
 97→		}
 98→	};
 99→
100→	// Use cached org as optimistic value while better-auth is still loading
101→	const resolvedOrg = activeOrg ?? (activeLoading ? cachedOrg : null);
102→
103→	return (
104→		<OrganizationContext.Provider
105→			value={{
106→				activeOrg: resolvedOrg,
107→				organizations: orgs ?? [],
108→				switchOrg,
109→				isLoading: activeLoading || listLoading || switching,
110→			}}
111→		>
112→			{children}
113→		</OrganizationContext.Provider>
114→	);
115→}
116→
117→export function useOrganization() {
118→	const context = useContext(OrganizationContext);
119→	if (context === undefined) {
120→		throw new Error(
121→			"useOrganization must be used within an OrganizationProvider",
122→		);
123→	}
124→	return context;
125→}
126→

 1→import { organizationClient } from "better-auth/client/plugins";
 2→import { createAuthClient } from "better-auth/react";
 3→import { queryClient } from "./query-client";
 4→
 5→export const authClient = createAuthClient({
 6→	baseURL: "",
 7→	plugins: [organizationClient()],
 8→});
 9→
10→export async function signOut() {
11→	await authClient.signOut();
12→	queryClient.clear();
13→	localStorage.removeItem("dateRange");
14→	localStorage.removeItem("globalFilters");
15→	localStorage.removeItem("rudel:activeOrg");
16→	// Notify all better-auth signal atoms to trigger refetches,
17→	// clearing stale org data that /sign-out doesn't reset
18→	for (const key of Object.keys(authClient.$store.atoms)) {
19→		if (key.startsWith("$")) {
20→			authClient.$store.notify(key);
21→		}
22→	}
23→}
