 1→import { getAllAdapters } from "@rudel/agent-adapters";
 2→import {
 3→	type ClickHouseExecutor,
 4→	escapeString,
 5→	getClickhouse,
 6→} from "../clickhouse.js";
 7→
 8→export async function getOrgSessionCount(orgId: string): Promise<number> {
 9→	const ch = getClickhouse();
10→	const escaped = escapeString(orgId);
11→	const tables = getAllAdapters().map((a) => a.rawTableName);
12→	const results = await Promise.all(
13→		tables.map((table) =>
14→			ch.query<{ count: string }>(
15→				`SELECT count() as count FROM ${table} WHERE organization_id = '${escaped}'`,
16→			),
17→		),
18→	);
19→	return results.reduce((sum, rows) => sum + Number(rows[0]?.count ?? 0), 0);
20→}
21→
22→export async function deleteOrgSessions(orgId: string): Promise<void> {
23→	const ch = getClickhouse();
24→	const escaped = escapeString(orgId);
25→	const tables = getAllAdapters().map((a) => a.rawTableName);
26→	await Promise.all([
27→		...tables.map((table) =>
28→			ch.execute(`DELETE FROM ${table} WHERE organization_id = '${escaped}'`),
29→		),
30→		ch.execute(
31→			`DELETE FROM rudel.session_analytics WHERE organization_id = '${escaped}'`,
32→		),
33→	]);
34→}
35→
36→export async function migrateOrgSessions(
37→	fromOrgId: string,
38→	toOrgId: string,
39→	ch: ClickHouseExecutor = getClickhouse(),
40→): Promise<void> {
41→	const from = escapeString(fromOrgId);
42→	const tables = getAllAdapters().map((a) => a.rawTableName);
43→
44→	// Can't use ALTER TABLE UPDATE — organization_id is an ORDER BY key and
45→	// ingested_at is the ReplacingMergeTree version column.
46→	// Can't use CREATE TABLE ... AS SELECT — ClickHouse Cloud has eventual
47→	// consistency across replicas, so the SELECT may read stale data.
48→	// Instead, read rows into the app, swap the org_id, and re-insert.
49→	await Promise.all(
50→		tables.map(async (table) => {
51→			const rows = await ch.query<Record<string, unknown>>(
52→				`SELECT * FROM ${table} WHERE organization_id = '${from}'`,
53→			);
54→			if (rows.length === 0) return;
55→			const migrated = rows.map((row) => ({
56→				...row,
57→				organization_id: toOrgId,
58→			}));
59→			await ch.insert({ table, values: migrated });
60→		}),
61→	);
62→
63→	// Delete old rows. On ClickHouse Cloud, DELETE mutations may outlast the
64→	// HTTP gateway timeout (504) but still run to completion server-side.
65→	// Fire all deletes in parallel and don't let a gateway timeout abort the
66→	// migration — the INSERT above already succeeded.
67→	const deletions = [
68→		...tables.map((table) =>
69→			ch.execute(`DELETE FROM ${table} WHERE organization_id = '${from}'`),
70→		),
71→		ch.execute(
72→			`DELETE FROM rudel.session_analytics WHERE organization_id = '${from}'`,
73→		),
74→	];
75→	const results = await Promise.allSettled(deletions);
76→	for (const r of results) {
77→		if (r.status === "rejected") {
78→			console.warn(
79→				`[migrateOrgSessions] DELETE mutation may still be running: ${r.reason}`,
80→			);
81→		}
82→	}
83→}
