  1→import { useQuery } from "@tanstack/react-query";
  2→import { AlertTriangle, Loader2 } from "lucide-react";
  3→import { useEffect, useState } from "react";
  4→import { client } from "../lib/orpc";
  5→import { Button } from "./ui/button";
  6→import {
  7→	Dialog,
  8→	DialogContent,
  9→	DialogDescription,
 10→	DialogFooter,
 11→	DialogHeader,
 12→	DialogTitle,
 13→} from "./ui/dialog";
 14→import { Input } from "./ui/input";
 15→
 16→interface DeleteOrganizationDialogProps {
 17→	open: boolean;
 18→	onOpenChange: (open: boolean) => void;
 19→	organization: { id: string; name: string };
 20→	otherOrganizations: { id: string; name: string }[];
 21→	onDeleted: () => void;
 22→}
 23→
 24→export function DeleteOrganizationDialog({
 25→	open,
 26→	onOpenChange,
 27→	organization,
 28→	otherOrganizations,
 29→	onDeleted,
 30→}: DeleteOrganizationDialogProps) {
 31→	const { data: sessionCountData, isLoading: loading } = useQuery({
 32→		queryKey: ["org-session-count", organization.id],
 33→		queryFn: async () => {
 34→			const res = await client.getOrganizationSessionCount({
 35→				organizationId: organization.id,
 36→			});
 37→			return res.count;
 38→		},
 39→		enabled: open,
 40→	});
 41→	const sessionCount = sessionCountData ?? null;
 42→	const [sessionAction, setSessionAction] = useState<
 43→		"migrate" | "delete" | null
 44→	>(null);
 45→	const [migrateTarget, setMigrateTarget] = useState("");
 46→	const [confirmName, setConfirmName] = useState("");
 47→	const [deleting, setDeleting] = useState(false);
 48→	const [error, setError] = useState<string | null>(null);
 49→
 50→	useEffect(() => {
 51→		if (!open) {
 52→			setSessionAction(null);
 53→			setMigrateTarget("");
 54→			setConfirmName("");
 55→			setDeleting(false);
 56→			setError(null);
 57→		}
 58→	}, [open]);
 59→
 60→	const nameMatches =
 61→		confirmName.toLowerCase() === organization.name.toLowerCase();
 62→	const canDelete =
 63→		nameMatches &&
 64→		!deleting &&
 65→		(sessionCount === 0 ||
 66→			sessionAction === "delete" ||
 67→			(sessionAction === "migrate" && migrateTarget));
 68→
 69→	const handleDelete = async () => {
 70→		setDeleting(true);
 71→		setError(null);
 72→		try {
 73→			await client.deleteOrganization({
 74→				organizationId: organization.id,
 75→				migrateSessionsTo:
 76→					sessionAction === "migrate" ? migrateTarget : undefined,
 77→			});
 78→			onDeleted();
 79→		} catch (err) {
 80→			setError(
 81→				err instanceof Error ? err.message : "Failed to delete organization",
 82→			);
 83→			setDeleting(false);
 84→		}
 85→	};
 86→
 87→	return (
 88→		<Dialog open={open} onOpenChange={onOpenChange}>
 89→			<DialogContent>
 90→				<DialogHeader>
 91→					<DialogTitle className="flex items-center gap-2">
 92→						<AlertTriangle className="h-5 w-5 text-red-500" />
 93→						Delete Organization
 94→					</DialogTitle>
 95→					<DialogDescription>
 96→						This action cannot be undone. This will permanently delete{" "}
 97→						<strong>{organization.name}</strong> and remove all member access.
 98→					</DialogDescription>
 99→				</DialogHeader>
100→
101→				{loading ? (
102→					<div className="flex items-center justify-center py-8">
103→						<Loader2 className="h-6 w-6 animate-spin text-muted" />
104→					</div>
105→				) : (
106→					<div className="flex flex-col gap-4">
107→						{sessionCount !== null && sessionCount > 0 ? (
108→							<>
109→								<p className="text-sm text-foreground">
110→									This organization has{" "}
111→									<strong>
112→										{sessionCount} session{sessionCount !== 1 ? "s" : ""}
113→									</strong>
114→									.
115→								</p>
116→
117→								<div className="flex flex-col gap-2">
118→									<label className="flex items-start gap-2 rounded-lg border border-border p-3 cursor-pointer has-[:checked]:border-foreground">
119→										<input
120→											type="radio"
121→											name="sessionAction"
122→											value="migrate"
123→											checked={sessionAction === "migrate"}
124→											onChange={() => setSessionAction("migrate")}
125→											className="mt-0.5"
126→										/>
127→										<div className="flex flex-col gap-1">
128→											<span className="text-sm font-medium text-foreground">
129→												Migrate sessions
130→											</span>
131→											<span className="text-xs text-muted">
132→												Move all sessions to another organization
133→											</span>
134→											{sessionAction === "migrate" && (
135→												<select
136→													value={migrateTarget}
137→													onChange={(e) => setMigrateTarget(e.target.value)}
138→													className="mt-1 rounded-md border border-border bg-surface px-3 py-1.5 text-sm text-foreground"
139→												>
140→													<option value="">Select organization...</option>
141→													{otherOrganizations.map((org) => (
142→														<option key={org.id} value={org.id}>
143→															{org.name}
144→														</option>
145→													))}
146→												</select>
147→											)}
148→										</div>
149→									</label>
150→
151→									<label className="flex items-start gap-2 rounded-lg border border-border p-3 cursor-pointer has-[:checked]:border-foreground">
152→										<input
153→											type="radio"
154→											name="sessionAction"
155→											value="delete"
156→											checked={sessionAction === "delete"}
157→											onChange={() => setSessionAction("delete")}
158→											className="mt-0.5"
159→										/>
160→										<div className="flex flex-col gap-1">
161→											<span className="text-sm font-medium text-foreground">
162→												Delete sessions
163→											</span>
164→											<span className="text-xs text-muted">
165→												Permanently delete all session data
166→											</span>
167→										</div>
168→									</label>
169→								</div>
170→							</>
171→						) : (
172→							<p className="text-sm text-muted">
173→								This organization has no session data.
174→							</p>
175→						)}
176→
177→						<div className="flex flex-col gap-2">
178→							<label htmlFor="confirm-name" className="text-sm text-foreground">
179→								Type <strong>{organization.name}</strong> to confirm:
180→							</label>
181→							<Input
182→								id="confirm-name"
183→								value={confirmName}
184→								onChange={(e) => setConfirmName(e.target.value)}
185→								placeholder={organization.name}
186→							/>
187→						</div>
188→
189→						{error && <p className="text-sm text-red-500">{error}</p>}
190→					</div>
191→				)}
192→
193→				<DialogFooter>
194→					<Button
195→						variant="outline"
196→						onClick={() => onOpenChange(false)}
197→						disabled={deleting}
198→					>
199→						Cancel
200→					</Button>
201→					<Button
202→						variant="destructive"
203→						onClick={handleDelete}
204→						disabled={!canDelete}
205→					>
206→						{deleting && <Loader2 className="h-4 w-4 animate-spin mr-2" />}
207→						Delete Organization
208→					</Button>
209→				</DialogFooter>
210→			</DialogContent>
211→		</Dialog>
212→	);
213→}
214→

  1→import { ORPCError } from "@orpc/server";
