122→const deleteOrganization = os.deleteOrganization
123→	.use(authMiddleware)
124→	.handler(async ({ input, context }) => {
125→		const orgId = input.organizationId;
126→		const userId = context.user.id;
127→		console.log(
128→			`[deleteOrganization] user=${userId} org=${orgId} migrateSessionsTo=${input.migrateSessionsTo ?? "none"}`,
129→		);
130→
131→		// Check user has more than one org
132→		const memberships = await db
133→			.select({ organizationId: member.organizationId })
134→			.from(member)
135→			.where(eq(member.userId, userId));
136→
137→		if (memberships.length <= 1) {
138→			console.log(
139→				`[deleteOrganization] rejected: user=${userId} has only ${memberships.length} org(s)`,
140→			);
141→			throw new ORPCError("BAD_REQUEST", {
142→				message: "Cannot delete your only organization",
143→			});
144→		}
145→
146→		// Verify user is owner of the target org
147→		const ownership = await db
148→			.select({ id: member.id })
149→			.from(member)
150→			.where(
151→				and(
152→					eq(member.organizationId, orgId),
153→					eq(member.userId, userId),
154→					eq(member.role, "owner"),
155→				),
156→			)
157→			.limit(1);
158→
159→		if (ownership.length === 0) {
160→			console.log(
161→				`[deleteOrganization] rejected: user=${userId} is not owner of org=${orgId}`,
162→			);
163→			throw new ORPCError("FORBIDDEN", {
164→				message: "Only the organization owner can delete it",
165→			});
166→		}
167→
168→		try {
169→			if (input.migrateSessionsTo) {
170→				if (input.migrateSessionsTo === orgId) {
171→					throw new ORPCError("BAD_REQUEST", {
172→						message: "Cannot migrate sessions to the same organization",
173→					});
174→				}
175→
176→				// Verify user is a member of the target org
177→				const targetMembership = await db
178→					.select({ id: member.id })
179→					.from(member)
180→					.where(
181→						and(
182→							eq(member.organizationId, input.migrateSessionsTo),
183→							eq(member.userId, userId),
184→						),
185→					)
186→					.limit(1);
187→
188→				if (targetMembership.length === 0) {
189→					console.log(
190→						`[deleteOrganization] rejected: user=${userId} not member of target org=${input.migrateSessionsTo}`,
191→					);
192→					throw new ORPCError("FORBIDDEN", {
193→						message: "Not a member of the target organization",
194→					});
195→				}
196→
197→				console.log(
198→					`[deleteOrganization] migrating sessions from org=${orgId} to org=${input.migrateSessionsTo}`,
199→				);
200→				await migrateOrgSessions(orgId, input.migrateSessionsTo);
201→				console.log(`[deleteOrganization] session migration complete`);
202→			} else {
203→				console.log(
204→					`[deleteOrganization] deleting ClickHouse sessions for org=${orgId}`,
205→				);
206→				await deleteOrgSessions(orgId);
207→				console.log(
208→					`[deleteOrganization] ClickHouse session deletion complete`,
209→				);
210→			}
211→
212→			// Delete the organization from Postgres (cascade handles member + invitation)
213→			console.log(`[deleteOrganization] deleting org=${orgId} from Postgres`);
214→			await db.delete(organization).where(eq(organization.id, orgId));
215→
216→			// Clear activeOrganizationId on user sessions that reference the deleted org
217→			console.log(
218→				`[deleteOrganization] clearing activeOrganizationId references for org=${orgId}`,
219→			);
220→			await db
221→				.update(session)
222→				.set({ activeOrganizationId: null })
223→				.where(eq(session.activeOrganizationId, orgId));
224→
225→			console.log(`[deleteOrganization] success for org=${orgId}`);
226→			return { success: true as const };
227→		} catch (error) {
228→			if (error instanceof ORPCError) throw error;
229→			console.error(`[deleteOrganization] failed for org=${orgId}:`, error);
230→			throw error;
231→		}
232→	});
