  1→import { createClient } from "@clickhouse/client-web";
  2→import { getLogger } from "@logtape/logtape";
  3→
  4→const logger = getLogger(["rudel", "api", "clickhouse"]);
  5→
  6→export interface ClickHouseExecutor {
  7→	execute(sql: string): Promise<void>;
  8→	query<T>(sql: string): Promise<T[]>;
  9→	insert(params: { table: string; values: object[] }): Promise<void>;
 10→}
 11→
 12→export function createClickHouseExecutor(config: {
 13→	url: string;
 14→	username?: string;
 15→	password?: string;
 16→	database?: string;
 17→}): ClickHouseExecutor {
 18→	const client = createClient({
 19→		url: config.url,
 20→		username: config.username,
 21→		password: config.password,
 22→		database: config.database,
 23→		request_timeout: 120_000,
 24→		clickhouse_settings: {
 25→			wait_end_of_query: 1,
 26→		},
 27→	});
 28→	return {
 29→		async execute(sql) {
 30→			await client.command({ query: sql });
 31→		},
 32→		async query<T>(sql: string): Promise<T[]> {
 33→			const result = await client.query({
 34→				query: sql,
 35→				format: "JSONEachRow",
 36→			});
 37→			return result.json();
 38→		},
 39→		async insert(params) {
 40→			// Use command() with FORMAT JSONEachRow instead of client.insert()
 41→			// because ClickHouse Cloud's @clickhouse/client insert() silently drops data.
 42→			const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
 43→			await client.command({
 44→				query: `INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
 45→			});
 46→		},
 47→	};
 48→}
 49→
 50→let _clickhouse: ClickHouseExecutor | null = null;
 51→
 52→export function getClickhouse(): ClickHouseExecutor {
 53→	if (!_clickhouse) {
 54→		const executor = createClickHouseExecutor({
 55→			url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
 56→			username:
 57→				process.env.CLICKHOUSE_USERNAME ||
 58→				process.env.CLICKHOUSE_USER ||
 59→				"default",
 60→			password: process.env.CLICKHOUSE_PASSWORD || "",
 61→			database: "default",
 62→		});
 63→		const maxRetries = 3;
 64→		_clickhouse = {
 65→			...executor,
 66→			async insert(params) {
 67→				for (let attempt = 0; attempt < maxRetries; attempt++) {
 68→					try {
 69→						return await executor.insert(params);
 70→					} catch (error) {
 71→						if (attempt === maxRetries - 1) {
 72→							logger.error(
 73→								"Insert into {table} failed after {maxRetries} attempts: {error}",
 74→								{ table: params.table, maxRetries, error },
 75→							);
 76→							throw error;
 77→						}
 78→						logger.warn(
 79→							"Insert into {table} failed (attempt {attempt}/{maxRetries}), retrying: {error}",
 80→							{
 81→								table: params.table,
 82→								attempt: attempt + 1,
 83→								maxRetries,
 84→								error,
 85→							},
 86→						);
 87→						await new Promise((r) => setTimeout(r, 100 * (attempt + 1)));
 88→					}
 89→				}
 90→			},
 91→		};
 92→	}
 93→	return _clickhouse;
 94→}
 95→
 96→export function escapeString(value: string): string {
 97→	return value.replace(/'/g, "\\'");
 98→}
 99→
100→export function buildDateFilter(days: number, column = "session_date"): string {
101→	return `${column} >= now64(3) - INTERVAL ${Number(days)} DAY AND ${column} <= now64(3)`;
102→}
103→
104→export async function queryClickhouse<T>(sql: string): Promise<T[]> {
105→	const ch = getClickhouse();
106→	return ch.query<T>(sql);
107→}
