 57→async function waitForRow(
 58→	table: string,
 59→	orgId: string,
 60→	sessionId: string,
 61→	timeoutMs = 30_000,
 62→	intervalMs = 2_000,
 63→): Promise<Array<{ session_id: string; organization_id: string }>> {
 64→	const start = Date.now();
 65→	while (Date.now() - start < timeoutMs) {
 66→		const results = await executor.query<{
 67→			session_id: string;
 68→			organization_id: string;
 69→		}>(
 70→			`SELECT session_id, organization_id FROM ${table} WHERE session_id = '${sessionId}' AND organization_id = '${orgId}' LIMIT 1`,
 71→		);
 72→		if (results.length > 0) return results;
 73→		await new Promise((r) => setTimeout(r, intervalMs));
 74→	}
 75→	return [];
 76→}
