 52→function corsHeaders(origin: string | null): Record<string, string> {
 53→	if (origin !== ALLOWED_ORIGIN) return {};
 54→	return {
 55→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 56→		"Access-Control-Allow-Credentials": "true",
 57→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 58→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 59→	};
 60→}
