 64→const server = Bun.serve({
 65→	port,
 66→	async fetch(request) {
 67→		const origin = request.headers.get("Origin");
 68→		const cors = corsHeaders(origin);
 69→
 70→		if (request.method === "OPTIONS") {
 71→			return new Response(null, { status: 204, headers: cors });
 72→		}
 73→
 74→		const url = new URL(request.url);
 75→
 76→		// Health check for Fly.io (must be GET-accessible)
 77→		if (url.pathname === "/health") {
 78→			return Response.json({ status: "ok", timestamp: Date.now() });
 79→		}
 80→
 81→		const requestId = crypto.randomUUID();
 82→		const start = performance.now();
 83→
 84→		return withContext(
 85→			{ requestId, method: request.method, path: url.pathname },
 86→			async () => {
 87→				const response = await handleRequest(request, url, cors);
 88→				const duration = Math.round(performance.now() - start);
 89→				logger.info("{method} {path} {status} {duration}ms", {
 90→					method: request.method,
 91→					path: url.pathname,
 92→					status: response.status,
 93→					duration,
 94→				});
 95→				return response;
 96→			},
 97→		);
 98→	},
 99→});
